import { DatePipe, formatNumber } from "@angular/common";
import { HttpClient } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { Router } from "@angular/router";
import { AlertController, Platform } from "@ionic/angular";
import { Subscription } from "rxjs";
import { EnvService } from "src/app/core/services/env.service";
import { LoanTracking } from "src/app/views/Models/Loan/LoanInfo";
import { ClientInfo } from "../../../Models/Client/ClientInfo";
import { SearchResult } from "../../../Models/References/SearchResult";
import { MohassilAuthService } from "src/app/core/services/AuthenticationServices/mohassil-auth.service";

@Component({
  selector: "app-loan-tracker",
  templateUrl: "./loan-tracker.page.html",
  styleUrls: ["./loan-tracker.page.scss"],
})
export class loantrackerPage {
  showLoader: boolean = false;
  isSubmitted: boolean = false;
  isvalids = false;

  constructor(
    private env: EnvService,
    private datepipe: DatePipe,
    private http: HttpClient,
    private formBuilder: FormBuilder,
    private platform: Platform,
    private router: Router,
    private alertController: AlertController,
    private authService: MohassilAuthService
  ) {}

  //#region Variables
  isTrackerForm: boolean = false;
  Tracking: LoanTracking[];
  isSearching: boolean = true;
  backButtonListener: Subscription;
  SearchResult: SearchResult;

  isIonAccordion: boolean = false;

  InfoOfEveryLoan: any;
  InstallmentsArray: any[];
  //#endregion

  async ngOnInit(): Promise<void> {
    this.registerBackButtonListener();
  }

  clientSelected(event: SearchResult) {
    this.SearchResult = event;
    this.showLoader = true;
    try {
      this.isSearching = false;
      this.http
        .post<LoanTracking[]>(this.env.API_URL + "api/Loan/TrackingLoan", {
          nation_id: event.nation_id,
        })
        .subscribe((data) => {
          this.Tracking = data;
          // changing in formats in Tracking Result
          for (let i = 0; i < this.Tracking.length; ) {
            this.Tracking[i].original_amount = formatNumber(
              Number(parseInt(this.Tracking[i].original_amount)),
              "en-US",
              "1.0-0"
            );
            this.Tracking[i].inst_int = formatNumber(
              Number(parseInt(this.Tracking[i].inst_int)),
              "en-US",
              "1.0-0"
            );
            this.Tracking[i].inst_am = formatNumber(
              Number(parseInt(this.Tracking[i].inst_am)),
              "en-US",
              "1.0-0"
            );
            this.Tracking[i].deserved_amount = formatNumber(
              Number(parseInt(this.Tracking[i].deserved_amount)),
              "en-US",
              "1.0-0"
            );
            this.Tracking[i].inst_mat_date = this.datepipe.transform(
              this.Tracking[i].inst_mat_date,
              "yyyy-MM-dd"
            );
            i++;
          }
          // put all loan_code together in array
          let distinct_loan_code_array: any[] = this.getDistinctValues(
            this.Tracking,
            "loan_code"
          );

          // here i get the info of every loan and put it in variable InfoOfEveryLoan
          this.InfoOfEveryLoan = distinct_loan_code_array.map((loanCode) =>
            this.Tracking.find((x) => x.loan_code === loanCode)
          );
          this.isIonAccordion = true;

          // put every installment with each other in array
          this.InstallmentsArray = distinct_loan_code_array
            .filter((code) => {
              return this.Tracking.some(
                (item) => item.loan_code.toString() === code.toString()
              );
            })
            .map((code) => {
              return this.Tracking.filter(
                (item) => item.loan_code.toString() === code.toString()
              );
            });

          this.isTrackerForm = true;
          this.showLoader = false;
        });
    } catch (error) {
      console.log(error);
      this.showLoader = false;
      this.showAlertNoReload(`خطأ في الصفحة : ${error}`);
    }
  }

  ngOnDestroy(): void {
    this.backButtonListener.unsubscribe();
  }
  // this method to get all available values from specific column in array
  getDistinctValues(data: any[], distinct_name: string): any[] {
    const values = data.map((item: any) => item[distinct_name]);
    const distinctValues = values.filter(
      (value: any, index: number, array: any[]) =>
        array.indexOf(value) === index
    );
    return distinctValues;
  }
  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        this.backButton();
      }
    );
  }
  backButton(): void {
    if (this.isSearching == true) {
      this.router.navigate(["/home"]);
    } else if (this.isTrackerForm == true) {
      this.isTrackerForm = false;
      this.isSearching = true;
    }
  }
  async showAlertNoReload(message: string): Promise<void> {
    let alert = this.alertController.create({
      header: "تنبيه",
      message: message,
      buttons: [
        {
          text: "OK",
          role: "OK",
        },
      ],
    });
    (await alert).present();
  }
  async showAlert(message: string): Promise<void> {
    let alert = this.alertController.create({
      header: "تنبيه",
      message: message,
      buttons: [
        {
          text: "OK",
          role: "OK",
          handler: () => {
            location.reload();
          },
        },
      ],
    });
    (await alert).present();
  }
  checker(input: string) {
    if (input == null) return "لا يوجد";
    else {
      if (input.includes("00:00:00")) {
        return input.split(" ")[0];
      } else {
        return input;
      }
    }
  }
  backToSearch() {
    if (!this.isSearching) {
      location.reload();
    }
  }
}
